    this.controller.openResultDetail(this.wheelResult);
    this.goToResult();
  }

  private dateLabel(): string {
    const d: Date = new Date();
    const weekdays: string[] = ['周日', '周一', '周二', '周三', '周四', '周五', '周六'];
    return `${d.getMonth() + 1}月${d.getDate()}日 ${weekdays[d.getDay()]}`;
  }
}

