  }

  private ingredients(): string[] {
    return this.dish === null ? [] : this.dish.ingredients;
  }

  private heroTags(): string[] {
    if (this.dish === null) {
      return [];
    }
    const tags: string[] = this.dish.moods.slice();
    if (this.dish.timeScenes.length > 0) {
      tags.push(this.dish.timeScenes[0]);
    }
    return tags;
  }
}

